/****** Notas ******/
INSERT [PreV2].[Notas] ([notClave], [NotNota], [NotNotaIng]) VALUES (276, N'1. La población presentada tiene un propósito exclusivamente estadístico: está calibrada para que, en las estimaciones de pobreza, la suma de la población municipal sea igual a la población de cada entidad federativa reportada con base en la información del MCS-ENIGH 2010 o del MEC 2015 publicados. Por lo anterior, estas cifras de población podrían diferir de las reportadas por el INEGI y el CONAPO a nivel municipal.¬2. El municipio de Bacalar (23010) en Quintana Roo fue creado en 2011 (anteriormente era parte del municipio de Othón P. Blanco (23004)), por lo que no se cuenta con información para 2010.¬3. En 2015 para los municipios  de Buenaventura (08010), Carichí (08012), Santa Isabel (08024), Temósachic (08063), Urique (08065) en Chihuahua; San Nicolás de los Ranchos (21138) en Puebla; Matías Romero Avendaño (20057), Santa María Chimalapa (20407), San Francisco Chindúa (20140), Santa María Petapa (20427) en Oaxaca y Gral. Plutarco Elías Calles (26070) en Sonora no se puede generar estimaciones de los indicadores debido a que no se dispone de la información como lo especifica el INEGI en la<a target="_blank" class="liga3" href=" http://internet.contenidos.inegi.org.mx/contenidos/productos/prod_serv/contenidos/espanol/bvinegi/productos/nueva_estruc/promo/eic_2015_presentacion.pdf"> Encuesta Intercensal 2015</a>.¬4. Las estimaciones municipales de los indicadores de pobreza han sido ajustadas a la información reportada a nivel estatal en el MCS-ENIGH 2010 (cifras 2010) o en el MEC 2015 del MCS-ENIGH (cifras 2015).', N'1. The presented population has an exclusively statistical purpose: it is calibrated so that, in the poverty estimates, the sum of the municipal population is equal to the population of each federal entity reported based on the information of the MCS-ENIGH 2010 or the MEC 2015 published. Therefore, these population figures may differ from those reported by INEGI and CONAPO at the municipal level. ¬2. The municipality of Bacalar (23010) in Quintana Roo was created in 2011 (previously it was part of the municipality of Othon P. Blanco (23004)), so there is no information available for 2010.¬3. In 2015 for the municipalities of Buenaventura (08010), Carichí (08012), Santa Isabel (08024), Temósachic (08063), Urique (08065) ??in Chihuahua; San Nicolás de los Ranchos (21138) in Puebla; Matías Romero Avendaño (20057), Santa María Chimalapa (20407), San Francisco Chindúa (20140), Santa María Petapa (20427) in Oaxaca and General Plutarco Elías Calles (26070) in Sonora can not generate estimates of the indicators due to that the information is not available, as specified by the INEGI in<a target = "_ blank" class = "liga3" href="http://internet.contenidos.inegi.org.mx/contenidos/productos/prod_serv/contenidos/espanol/bvinegi/productos/nueva_estruc/promo/eic_2015_presentacion.pdf"> the Intercensal Survey 2015</a>.¬4. The municipal estimates of the poverty indicators have been adjusted to the information reported at the state level in the MCS-ENIGH 2010 (figures 2010) or in the 2015 MEC of the MCS-ENIGH (figures 2015).')
INSERT [PreV2].[Notas] ([notClave], [NotNota], [NotNotaIng]) VALUES (300, N'Para 2014, 2015, 2016,2017 y 2018 cifras al cuarto trimestre. Para 2019 cifras del primer trimestre. No se incluyen líneas de telefonía pública.', N'For 2014, 2015, 2016,2017 and 2018 figures for the fourth quarter. For 2019 first quarter figures. Public telephone lines are not included.')

