INSERT [PreV2].[Fuentes] ([fueClave], [fueDescrip], [fueDescripIng]) VALUES (504, N'Instituto Federal de Telecomunicaciones (IFT), Coordinación General de Planeación Estratégica, con información proporcionada por los concesionarios.', N'Instituto Federal de Telecomunicaciones (IFT), Coordinación General de Planeación Estratégica, with information provided by the concessionaires.')
INSERT [PreV2].[Fuentes] ([fueClave], [fueDescrip], [fueDescripIng]) VALUES (516, N'Estimaciones del CONEVAL con base en información del INEGI. Para nacional y entidad federativa: MCS-ENIGH 2008 - 2014 y el MEC del MCS-ENIGH 2016 y 2018. Para municipios:  MCS-ENIGH 2010, la muestra del Censo de Población y Vivienda 2010, el Modelo estadístico 2015 (MEC 2015) para la continuidad del MCS-ENIGH y la Encuesta Intercensal 2015.', N'CONEVAL estimates based on information from INEGI. For national and federative entity: MCS-ENIGH 2008 - 2014 and the MEC of MCS-ENIGH 2016 and 2018. For municipalities: MCS-ENIGH 2010, the sample of the Population and Housing Census 2010, the Statistical Model 2015 (MEC 2015) for the continuity of the MCS-ENIGH and the Intercensal Survey 2015.')

